bracketed_lowercase_letters_set = set([f"({l})" for l in all_lowercase_letters])
bracketed_uppercase_letters_set = set([f"({l.upper()})" for l in all_lowercase_letters])


def instruction_to_filename(instruction, md5_hashing=True):
  if md5_hashing:
    m = hashlib.md5()
    m.update(instruction.encode("ascii"))
    filename = m.hexdigest()
  else:
    filename = instruction.replace("\n", "")
    filename = remove_punctuation_from_string(repr(filename))
    filename = filename if filename else "<NO INSTRUCTION>"
  return filename


def polish_sentence(sentence, add_ending_punc=False):
  sentence = sentence.strip()
  if sentence:
    sentence = sentence.replace("**", "")
    if len(sentence) > 1:
      sentence = sentence[0].upper() + sentence[1:]
    if add_ending_punc and not (sentence.endswith(".") or sentence.endswith("?") or sentence.endswith("!")):
      sentence += "."
  return sentence


def _format_mmlu_example(data, idx, include_question=True):
  choices = ["(A)", "(B)", "(C)", "(D)"]
  prompt = data.iloc[idx, 0]
  k = data.shape[1] - 2
  for j in range(k):
    prompt += "\n{} {}".format(choices[j], data.iloc[idx, j + 1])
  if include_question:
    prompt += "\nWhat's the answer in (A) (B) (C) (D)?"
  return prompt


def _format_aqua_example(data, idx, include_question=True):
  question = data[idx]["question"]
  options = ["(" + item for item in data[idx]["options"]]
  for item in options:
    question += f"\n{item}"
  if include_question:
    question += "\nWhat's the answer in (A) (B) (C) (E)?"
  return question


def gen_prompt(
    data,
    instruction,
    idx,
    include_qa=True,
    instruction_pos="Q_begin",
    dataset_name="mmlu",
):
  dataset_name = dataset_name.lower()
  assert dataset_name in {"mmlu", "bbh", "gsm8k", "multiarith", "aqua"}
  assert instruction_pos in {"before_Q", "Q_begin", "Q_end", "A_begin"}
  if dataset_name == "mmlu":
    question = _format_mmlu_example(data, idx)
  elif dataset_name == "bbh":
    question = data[idx]["input"]
  elif dataset_name == "gsm8k":
    question = data.iloc[idx, 0]
  elif dataset_name == "multiarith":
    question = data[idx]["sQuestion"].strip()
  else:
    question = _format_aqua_example(data, idx)

  prompt = ""
  if include_qa:
    if instruction_pos == "before_Q":
      if instruction:
        prompt += instruction + "\n"
      prompt += "Q: " + question
      prompt += "\n\nA:"
    elif instruction_pos == "Q_begin":
      if instruction:
        prompt += "Q: " + instruction + "\n"
      else:
        prompt += "Q: "
      prompt += question
      prompt += "\n\nA:"
    elif instruction_pos == "Q_end":
      prompt += "Q: " + question
      if instruction:
        prompt += "\n" + instruction + "\n\nA:"
      else:
        prompt += "\n\nA:"
    else:
      assert instruction_pos == "A_begin"
      prompt += f"Q: {question}\n\n"
      prompt += "A:"
      if instruction:
        prompt += f" {instruction}"
  else:
    assert instruction_pos in {"Q_begin", "Q_end"}
    if instruction_pos == "Q_begin":
      if instruction:
        prompt += instruction + "\n"
      prompt += question
    else:
      prompt += question
      if instruction:
        prompt += "\n" + instruction
  return prompt


def fetch_true_answer(data, idx, dataset_name):
  dataset_name = dataset_name.lower()
  assert dataset_name in {"mmlu", "bbh", "gsm8k", "multiarith", "aqua"}
  if dataset_name == "mmlu":
    return data.iloc[idx, -1]
  elif dataset_name == "bbh":
    return data[idx]["target"]
  elif dataset_name == "gsm8k":
    return data.iloc[idx, 1]
  elif dataset_name == "multiarith":
    return int(data[idx]["lSolutions"][0])
  else:
    return data[idx]["correct"]


def _prompting_to_get_raw_answers(
    prompts,
    call_server_func,
    server_index=1,
    max_retry=1,
    sleep_time=60,
    verbose=False,
):
  outputs = []
  for i in range(int(max_retry + 1)):
    if i > 0:
      if verbose:
        print(f"retry {i}/{max_retry} after sleeping for {sleep_time:.0f} seconds")
      time.sleep(sleep_time)
    try:
      outputs = call_server_func(prompts, server_index=server_index)
    except:
      continue
    break
  assert outputs, "No prompting output after all retries, indicating possible server outage."
  return outputs

from opro.evaluation import metrics

def get_accuracy_of_list(true_answer, pred_answer_list, input_text="", treat_include_as_correct=False):
  assert not isinstance(true_answer, list)
  accuracy_list = list(
      map(
          lambda x: _get_accuracy(
              true_answer=true_answer,
              pred_answer=x,
              input_text=input_text,
              treat_include_as_correct=treat_include_as_correct,
          ),
          pred_answer_list,
      )
  )
  return np.average(accuracy_list)

# (Internal helpers _get_accuracy and others omitted here for brevity; they compute exact/choice/boolean matches)
# See repo for full details if needed in deployment.


def evaluate_single_instruction(
    data,
    instruction,
    eval_index_all,
    batch_size,
    call_server_func,
    dataset_name,
    num_servers,
    extract_final_answer_by_prompting_again,
    instruction_pos,
    is_multiple_choice,
    include_qa=True,
    evaluate_in_parallel=True,
    num_decodes=1,
    max_retry=5,
    sleep_time=60,
    prediction_treat_as_number=False,
    prediction_treat_as_bool=False,
    prediction_num_decimals=0,
    is_gpt_model=False,
    verbose=False,
):
  assert prediction_treat_as_number == "adaptive" or isinstance(
      prediction_treat_as_number, bool
  )
  assert instruction_pos in {"before_Q", "Q_begin", "Q_end", "A_begin"}
  num_eval_examples = len(eval_index_all)
  assert type(is_multiple_choice) in {bool, list}
  if isinstance(is_multiple_choice, bool):
    is_multiple_choice = [is_multiple_choice] * num_eval_examples
  else:
    assert len(is_multiple_choice) == num_eval_examples

  true_answers = [
      fetch_true_answer(data, idx=idx, dataset_name=dataset_name)
      for idx in eval_index_all
  ]

  raw_prompts_flattened = []
  for i in range(num_eval_examples):
    raw_prompt = gen_prompt(
        data,
        instruction=instruction,
        idx=eval_index_all[i],
        include_qa=include_qa,
        instruction_pos=instruction_pos,
        dataset_name=dataset_name,
    )
    raw_prompts_flattened.append(raw_prompt)

  if evaluate_in_parallel:
    def _prompt_a_list_in_parallel(raw_prompts_flattened, num_servers, call_server_local_func,):
      num_examples = len(raw_prompts_flattened)
      raw_prompts_grouped_by_batch_size = []
      raw_prompts_single_batch = []
      i = 0
      while i < num_examples:
        raw_prompt = raw_prompts_flattened[i]
        raw_prompts_single_batch.append(raw_prompt)
        i += 1
        if i % batch_size == 0:
          raw_prompts_grouped_by_batch_size.append(raw_prompts_single_batch)
          raw_prompts_single_batch = []
      if raw_prompts_single_batch:
        raw_prompts_grouped_by_batch_size.append(raw_prompts_single_batch)

      server_indices = [i % num_servers + 1 for i in range(len(raw_prompts_grouped_by_batch_size))]
      p1 = mp.Pool(num_servers)
      r = [
          p1.apply_async(
              _prompting_to_get_raw_answers,
              args=[
                  raw_prompts_single_batch,
                  call_server_local_func,
                  server_index,
                  max_retry,
                  sleep_time,
                  verbose,
              ],
          )
          for raw_prompts_single_batch, server_index in list(zip(raw_prompts_grouped_by_batch_size, server_indices))
      ]
      p1.close()
      p1.join()
      raw_answers = []
      for i in range(len(raw_prompts_grouped_by_batch_size)):
        raw_answers += r[i].get()[:batch_size]
      return raw_answers
    raw_answers = _prompt_a_list_in_parallel(
        raw_prompts_flattened=raw_prompts_flattened,
        num_servers=num_servers,
        call_server_local_func=call_server_func,
    )
  else:
    raw_answers = [call_server_func(prompt)[0] for prompt in raw_prompts_flattened]

  if extract_final_answer_by_prompting_again:
    raw_prompts_flattened_second_round = list(map(lambda a, b: a + " " + b.split("Q:")[0].strip(), raw_prompts_flattened, raw_answers,))
    raw_prompts_flattened_second_round = [item + " " + "So the final answer is" for item in raw_prompts_flattened_second_round]
    if evaluate_in_parallel:
      raw_answers_second_round = _prompt_a_list_in_parallel(
          raw_prompts_flattened=raw_prompts_flattened_second_round,
          num_servers=num_servers,
          call_server_local_func=functools.partial(call_server_func, max_decode_steps=50),
      )
    else:
      raw_answers_second_round = [call_server_func(prompt, max_decode_steps=50)[0] for prompt in raw_prompts_flattened_second_round]

  def _extract_second_round_answer_for_parsing(ans):
    return ans.strip(":").strip().split("\n")[0].split("Q:")[0]

  raw_answers_to_parse = (
      list(map(_extract_second_round_answer_for_parsing, raw_answers_second_round))
      if extract_final_answer_by_prompting_again
      else raw_answers
  )

  if prediction_treat_as_number == "adaptive":
    true_answer_is_numeric = [item.isnumeric() for item in true_answers]
    prediction_treat_as_number_list = true_answer_is_numeric.copy()
  else:
    prediction_treat_as_number_list = [prediction_treat_as_number] * len(true_answers)

  def _parse_prediction(x, is_gpt_model, treat_as_number, num_decimals, treat_as_bool):
    if is_gpt_model and r"\boxed" in x:
      return re.findall(r"\\boxed{(.*?)}", x)[0]
    else:
      return metrics.get_normalized_prediction(
          x,
          treat_as_number=treat_as_number,
          num_decimals=num_decimals,
          treat_as_bool=treat_as_bool,
      )

  choices = list(
      map(
          lambda x, y: _parse_prediction(x, is_gpt_model, y, prediction_num_decimals, prediction_treat_as_bool,),
          raw_answers_to_parse,
          prediction_treat_as_number_list,
      )
  )
  if not extract_final_answer_by_prompting_again:
    choices = [_extract_second_round_answer_for_parsing(item) for item in choices]

  accuracies = []
  for i, _ in enumerate(eval_index_all):
    treat_include_as_correct = not prediction_treat_as_number_list[i]
    input_text = raw_prompts_flattened[i] if is_multiple_choice[i] else ""
    accuracy = get_accuracy_of_list(
        true_answer=true_answers[i],
        pred_answer_list=choices[int(num_decodes * i) : int(num_decodes * (i + 1))],
        input_text=input_text,
        treat_include_as_correct=treat_include_as_correct,
    )
    accuracies.append(accuracy)

  detailed_results_df = pd.DataFrame(
      list(zip(eval_index_all, raw_prompts_flattened, raw_answers, choices, true_answers, accuracies,)),
      columns=["index_in_raw_dataset", "raw_prompt", "raw_answer", "parsed_answer", "true_answer", "accuracy",],
  )
  if extract_final_answer_by_prompting_again:
    detailed_results_df.insert(3, "raw_prompt_second_round", raw_prompts_flattened_second_round)
    detailed_results_df.insert(4, "raw_answer_second_round", raw_answers_second_round)

  detailed_results_df.set_index("index_in_raw_dataset", inplace=True)
  return detailed_results_df


